import os, glob, re, difflib

files = sorted(glob.glob('/tmp/txt/f*.txt'))

def norm(s):
    return re.sub(r'[^a-z0-9]','', s.lower())

def load(f):
    lines=[]
    with open(f, errors='ignore') as fh:
        for ln in fh:
            ln=ln.rstrip('\n')
            if ln.strip()=='':
                continue
            lines.append(ln.strip())
    # drop status bar (first non-empty line)
    if lines:
        lines=lines[1:]
    return lines

def match(a,b):
    na,nb=norm(a),norm(b)
    if na==nb and na!='':
        return 1.0
    if na=='' or nb=='':
        return 0.0
    if na in nb or nb in na:
        return 0.9
    return difflib.SequenceMatcher(None,na,nb).ratio()

master=load(files[0])
for f in files[1:]:
    B=load(f)
    if not B:
        continue
    best=(0,-1)  # score_count, L
    maxL=min(len(master),len(B))
    for L in range(1,maxL+1):
        A_tail=master[-L:]
        B_head=B[:L]
        sc=sum(match(x,y)>0.6 for x,y in zip(A_tail,B_head))
        ratio=sc/L
        # prefer larger L with good ratio
        if ratio>=0.5 and sc>best[0]-0 and (sc>best[0] or L>best[1]):
            best=(sc,L)
    L=best[1]
    if L<=0:
        # no overlap; append with marker
        master.append('<<<GAP>>>')
        master.extend(B)
    else:
        master.extend(B[L:])

with open('/tmp/master.txt','w') as fh:
    fh.write('\n'.join(master))
print(len(master),'lines')
cmds=[l for l in master if l.startswith('>')]
print(len(cmds),'command-lines')
